import { useState, useEffect } from "react";

const SIGNOS = ["Aries","Tauro","Géminis","Cáncer","Leo","Virgo","Libra","Escorpión","Sagitario","Capricornio","Acuario","Piscis"];
const TOTAL_DAYS = 47;
const RETRATO_B64 = "data:image/jpeg;base64,";

const CONTENIDO = {
  "Aries":       { desc:"Es un hombre de mirada intensa y sonrisa cálida. Tiene una energía protectora y apasionada que complementa perfectamente tu fuego interior. Es directo, leal y profundamente romántico cuando encuentra a su persona. Su presencia transmite seguridad y su voz tiene el poder de calmar cualquier tormenta en tu corazón.", h1:"Se conocerán en un momento inesperado, quizás en una reunión de amigos o en un lugar que frecuentas. Él te notará primero. Habrá una mirada que lo dirá todo antes de que cualquier palabra sea pronunciada. Sentirás que ya lo conocías de antes.", h2:"El universo los acercará a través de una coincidencia que parecerá imposible. Un mensaje, una llamada, un lugar en común. Cuando menos lo esperes, él aparecerá en tu vida como si siempre hubiera pertenecido a ella.", r1n:"Ritual de la Vela Roja", r1d:"Enciende una vela roja cada viernes por la noche. Cierra los ojos, visualiza su llegada y di en voz alta: El amor que me pertenece viene hacia mí. Déjala consumirse completamente.", r1e:"🕯️", r2n:"Baño de Rosas", r2d:"Prepara un baño con pétalos de rosa roja y una cucharada de miel. Mientras te bañas, visualiza el encuentro con tu alma gemela. Agradece al universo como si ya hubiera llegado.", r2e:"🌹", r3n:"Carta al Universo", r3d:"Escribe una carta describiendo cómo te sientes junto a tu alma gemela usando tiempo presente. Guárdala bajo tu almohada por 7 noches y luego quémala liberando la intención al universo.", r3e:"✨", fin:"El universo ya escuchó tu corazón. Lo que es tuyo está en camino. Confía, prepárate y mantén tu corazón abierto. El amor verdadero no llega cuando lo buscas, llega cuando estás lista para recibirlo." },
  "Tauro":       { desc:"Es un hombre sereno y confiable, con una presencia que inspira paz inmediata. Tiene valores profundos y busca una conexión verdadera, no superficial. Es detallista, romántico a su manera y extremadamente leal. Cuando ama, ama para siempre. Su energía es como una raíz firme que te dará estabilidad y hogar.", h1:"Se encontrarán en un ambiente tranquilo y familiar — quizás un café, una librería o una reunión íntima. Él se acercará con calma, sin prisa. La conversación fluirá naturalmente y sentirás que el tiempo se detiene a su lado.", h2:"Alguien cercano a ti será el puente. Un amigo en común, un familiar o una situación cotidiana los unirá. No será dramático ni repentino — será suave y profundo, como todo lo que está destinado a durar.", r1n:"Ritual de la Tierra", r1d:"Planta una semilla o cuida una planta cada semana pensando en tu amor. Habla con la planta como si hablaras con él, expresando lo que sientes. La naturaleza amplifica la energía del amor estable.", r1e:"🌱", r2n:"Cristal de Cuarzo Rosa", r2d:"Consigue un cuarzo rosa y duérmete con él en la mano durante 7 noches. Cada noche repite: El amor estable y verdadero llega a mí con facilidad y gracia total.", r2e:"💎", r3n:"Ofrenda de Miel", r3d:"Coloca un pequeño recipiente con miel en tu mesita de noche. Cada mañana toca la miel con tu dedo anular y di: Endulzo mi camino al amor. Hazlo durante 21 días consecutivos.", r3e:"🍯", fin:"La paciencia es tu mayor virtud. Tu alma gemela está construyendo el camino hacia ti. El amor que mereces es sólido, real y eterno. Pronto sentirás su presencia llenando todos los espacios vacíos de tu corazón." },
  "Géminis":     { desc:"Es un hombre inteligente y con gran sentido del humor que igualará tu mente brillante. Sabe escucharte de verdad y estimulará tu curiosidad constantemente. Es versátil, comunicativo y tiene una chispa especial. Con él cada día será una nueva aventura y cada conversación dejará huella profunda en tu alma.", h1:"Se conocerán a través de la comunicación — quizás en redes, en un evento cultural o en una conversación grupal. Será su inteligencia lo que te atraiga primero. Una frase, una idea diferente que te hará querer saber más de él.", h2:"El destino los pondrá en el mismo lugar en el momento exacto. Podría ser un evento, un curso o una actividad que ambos eligieron por separado. La coincidencia será tan perfecta que ambos sonreirán al darse cuenta.", r1n:"Ritual de las Palabras", r1d:"Escribe cada noche tres cualidades que deseas en tu alma gemela. Léelas en voz alta mirando tu reflejo en el espejo. Las palabras tienen poder creador y el universo las escucha y actúa.", r1e:"📝", r2n:"Incienso de Lavanda", r2d:"Quema incienso de lavanda cada noche antes de dormir. Mientras el humo sube visualiza conversaciones profundas y risas con tu persona ideal. Permite que la imagen sea lo más vívida posible.", r2e:"🌿", r3n:"Ritual de Luna Nueva", r3d:"En cada luna nueva escribe en papel lo que deseas en el amor. Léelo en voz alta bajo el cielo nocturno. Dobla el papel y guárdalo hasta la luna llena, luego quémalo liberando tu deseo.", r3e:"🌙", fin:"Tu mente brillante ya sabe que él existe. El universo está alineando los detalles perfectos para su encuentro. Sigue siendo tú misma — es exactamente esa autenticidad lo que lo atraerá hacia ti." },
  "Cáncer":      { desc:"Es un hombre profundamente sensible y protector que entenderá tu mundo emocional sin que tengas que explicarlo. Tiene un corazón enorme y valora el hogar, la familia y los momentos íntimos. Es el tipo de hombre que recuerda los detalles pequeños y hace que te sientas completamente amada y segura.", h1:"Se conocerán en un entorno familiar o íntimo. Quizás una cena, un evento familiar de amigos o un lugar acogedor. Habrá algo en su mirada que te hará sentir vista de verdad por primera vez en mucho tiempo.", h2:"La conexión llegará de forma gradual y hermosa. Empezará como una amistad, como una conversación cómoda. Sin que ninguno lo planee, algo más profundo comenzará a crecer entre ustedes naturalmente.", r1n:"Ritual del Agua", r1d:"Cada luna llena vierte agua en un recipiente plateado o blanco bajo la luz lunar. Al día siguiente usa esa agua para lavarte la cara afirmando: Recibo el amor que merezco con el corazón abierto.", r1e:"🌊", r2n:"Vela Plateada", r2d:"Enciende una vela plateada los lunes — día de la luna — y visualiza un hogar cálido compartido con tu alma gemela. Siente la paz y el amor de ese espacio como si ya fuera real.", r2e:"🌕", r3n:"Diario del Amor", r3d:"Escribe cada noche una entrada en un diario sobre tu relación ideal como si ya existiera. Describe momentos, sensaciones y felicidad. La escritura consciente programa tu realidad amorosa.", r3e:"📖", fin:"Tu corazón sensible merece un amor que lo cuide con la misma intensidad que tú das. Ese hombre existe y te está buscando. El universo está acercando sus pasos a los tuyos en este momento." },
  "Leo":         { desc:"Es un hombre seguro de sí mismo pero con una ternura genuina que pocas personas conocen. Admira tu fuerza y brillo en lugar de sentirse amenazado por ellos. Es generoso, apasionado y sabe cómo hacerte sentir la mujer más especial del mundo. Juntos crearán una historia épica de amor y poder.", h1:"Se conocerán en un momento donde tú estás brillando — cuando estés siendo completamente tú misma, confiada y radiante. Él quedará cautivado de inmediato. No podrá evitar acercarse a ti porque tu luz lo atrae.", h2:"El encuentro ocurrirá en un espacio social, quizás un evento especial o una celebración. Él destacará entre todos y algo hará que sus miradas se encuentren repetidamente hasta que uno de los dos tome la iniciativa.", r1n:"Ritual del Sol", r1d:"Cada domingo a la mañana sal al sol por 10 minutos. Con los ojos cerrados y el rostro hacia el cielo di: Mi amor llega con la misma intensidad y calor que este sol. Soy digna de un amor extraordinario.", r1e:"☀️", r2n:"Vela Dorada", r2d:"Enciende una vela dorada o amarilla los domingos. Mientras arde, lista mentalmente todo lo que tienes para ofrecer en el amor. El reconocimiento de tu propio valor atrae a quien te merece.", r2e:"✨", r3n:"Afirmaciones de Poder", r3d:"Cada mañana frente al espejo di 5 veces: Soy digna del amor más grande y extraordinario. Mi alma gemela me ve, me admira y me elige cada día. Siente cada palabra en tu cuerpo.", r3e:"👑", fin:"Eres una mujer extraordinaria que merece un amor igualmente extraordinario. Él ya existe y está siendo preparado para estar a tu altura. Sigue brillando — esa luz es exactamente lo que lo guía hacia ti." },
  "Virgo":       { desc:"Es un hombre inteligente, detallista y con una profundidad emocional que no muestra fácilmente. Pero contigo será diferente. Verá tu esencia con una claridad asombrosa y valorará cada aspecto de quien eres. Es el tipo de hombre que demuestra el amor con acciones concretas y presencia genuina cada día.", h1:"Se conocerán en un contexto donde ambos están siendo productivos o aprendiendo algo. Quizás un ambiente de trabajo, estudio o una actividad que requiera concentración. Él notará tu inteligencia antes que cualquier otra cosa.", h2:"Una situación donde necesitas ayuda o donde puedes ofrecer la tuya será el punto de conexión. Habrá un intercambio práctico que se convertirá en algo mucho más significativo y bello de lo que cualquiera anticipó.", r1n:"Ritual de Hierbas", r1d:"Prepara una infusión de romero y lavanda. Mientras la bebes visualiza con claridad las cualidades de tu alma gemela y agradece por su llegada. El romero activa la memoria del alma y atrae lo que ya te pertenece.", r1e:"🌿", r2n:"Lista Sagrada", r2d:"Escribe en papel la lista definitiva de lo que buscas en el amor. Sé específica y honesta. Coloca la lista en un sobre cerrado bajo una vela blanca encendida. Quema la vela hasta consumirla.", r2e:"📋", r3n:"Orden y Amor", r3d:"Limpia y ordena profundamente el espacio que ocupará tu pareja en tu vida — un lado de la cama, espacio en el clóset. Este acto físico le dice al universo que estás lista para recibirlo.", r3e:"🏡", fin:"Tu capacidad de dar amor con dedicación y detalle es un regalo extraordinario. El hombre que llega a tu vida sabrá reconocer y valorar cada parte de quien eres. Él está más cerca de lo que imaginas." },
  "Libra":       { desc:"Es un hombre equilibrado y romántico por naturaleza, que comparte tu amor por la belleza y la armonía. Sabe comunicarse con elegancia y tiene un don especial para hacerte sentir comprendida y valorada. Es justo, considerado y buscará construir contigo una relación basada en el respeto y la admiración mutua.", h1:"Se conocerán en un ambiente estético y armonioso — un evento artístico, cultural o social. La primera impresión será poderosa para ambos. Habrá una elegancia natural en el encuentro que lo hará memorable e irrepetible.", h2:"El equilibrio de los dos mundos los acercará. Quizás compartan gustos similares o amigos en común. La conexión inicial será intelectual y estética, y desde ahí crecerá hasta tocar las capas más profundas del alma.", r1n:"Ritual del Espejo", r1d:"Cada noche antes de dormir mírate al espejo durante 3 minutos con amor genuino. Di: Soy digna del amor más hermoso y equilibrado. Lo que proyecto vuelve a mí multiplicado en amor verdadero.", r1e:"🪞", r2n:"Flores Blancas", r2d:"Coloca flores blancas frescas en tu hogar cada semana. Mientras las arreglas piensa en el amor que deseas recibir. Las flores blancas son símbolo de amor puro y elevan la energía amorosa del espacio.", r2e:"🌸", r3n:"Cristal de Amatista", r3d:"Medita con una amatista sobre tu corazón durante 10 minutos cada tarde. Visualiza una relación armoniosa y equilibrada. La amatista sintoniza tu energía con la frecuencia del amor verdadero.", r3e:"💜", fin:"El universo está creando el equilibrio perfecto para tu vida amorosa. El hombre que llega a ti traerá la armonía que tanto buscas. Tu alma gemela está siendo guiada hacia ti en el momento divino exacto." },
  "Escorpión":   { desc:"Es un hombre intenso y magnético que no teme la profundidad emocional — al contrario, la busca. Es transformador, apasionado y extraordinariamente leal con quien gana su confianza. Con él vivirás el tipo de amor que te cambia para siempre, el que deja huella en el alma y no se olvida jamás.", h1:"Se conocerán en un momento de vulnerabilidad o transformación personal de alguno de los dos. La conexión será inmediata, intensa y algo misteriosa. Sentirás que hay algo diferente en esta persona, como si el universo lo hubiera enviado especialmente.", h2:"El encuentro tendrá algo de inevitable. Quizás hayan estado cerca antes sin saberlo. Cuando finalmente se vean, la sensación de reconocimiento mutuo será tan fuerte que ambos quedarán sin palabras por un instante.", r1n:"Ritual de Transformación", r1d:"Escribe en papel todo lo que quieres liberar del pasado amoroso. Léelo en voz alta y quémalo con seguridad conscientemente. Desde las cenizas nace el amor más poderoso y verdadero de tu vida.", r1e:"🔥", r2n:"Baño de Luna", r2d:"La noche de luna llena date un baño con agua fría o tibia al que añadas sal negra o sal marina gruesa. Visualiza cómo se disuelven todas las barreras que impiden la llegada de tu amor verdadero.", r2e:"🌑", r3n:"Meditación Profunda", r3d:"Medita 10 minutos diarios enfocada en tu centro. Visualiza una luz carmesí en tu corazón que crece y se expande. Esta energía activa tu capacidad magnética de atracción amorosa poderosa.", r3e:"💗", fin:"Tu capacidad de amar profundamente es tu mayor poder. El hombre que llega a tu vida será digno de esa intensidad y la sabrá honrar. El amor transformador que buscas ya está siendo preparado para ti." },
  "Sagitario":   { desc:"Es un hombre aventurero y filosófico que comparte tu amor por la libertad y la expansión. No intentará limitarte — al contrario, te invitará a crecer y explorar juntos. Es optimista, generoso con su corazón y tiene una visión del mundo que complementa perfectamente la tuya en todos los aspectos.", h1:"Se conocerán en un contexto de aventura, viaje o aprendizaje. Quizás en un viaje, un curso, un evento internacional o conversando sobre sueños grandes. Él tendrá una visión del mundo que te expandirá la mente y el corazón.", h2:"La distancia no será obstáculo — podría ser alguien de otro lugar que llega a tu vida. O quizás alguien conocido que de repente ves con ojos completamente nuevos. El universo usará el movimiento para acercarlos.", r1n:"Ritual del Viaje", r1d:"Coloca un mapa o imagen de un lugar que sueñas visitar en tu cuarto. Cada noche visualízate ahí con tu alma gemela. El sueño compartido es una poderosa señal de atracción hacia tu persona ideal.", r1e:"🗺️", r2n:"Flecha de Intención", r2d:"Dibuja una flecha apuntando hacia arriba en papel. Escribe dentro lo que deseas en el amor. Colócala en tu ventana para que la luz del sol la toque cada mañana activando tu intención amorosa.", r2e:"🏹", r3n:"Meditación de Expansión", r3d:"Medita al aire libre cuando sea posible. Siente cómo tu energía amorosa se expande más allá de tu cuerpo, más allá de tu ciudad, hasta encontrar el alma que te busca en algún lugar del mundo.", r3e:"🌎", fin:"Tu espíritu libre y aventurero merece un compañero que lo celebre en lugar de limitarlo. Ese hombre existe y tiene el mismo fuego en el alma que tú. El universo los está acercando a través de la expansión." },
  "Capricornio": { desc:"Es un hombre maduro, ambicioso y con una solidez que te dará la seguridad que mereces. No juega con los sentimientos — cuando elige, elige con convicción y para siempre. Es el tipo de hombre que construye, que protege y que demuestra el amor con hechos concretos más que con palabras vacías.", h1:"Se conocerán en un contexto profesional o de crecimiento personal. Él reconocerá tu ambición y determinación inmediatamente. La atracción empezará desde el respeto mutuo y desde ahí se convertirá en algo mucho más profundo.", h2:"El tiempo será su aliado. Quizás ya se han cruzado pero el momento no era el correcto. Cuando ambos estén en el punto justo de sus vidas, el universo los pondrá frente a frente con una claridad perfecta.", r1n:"Ritual de la Montaña", r1d:"Busca una piedra pequeña y sólida. Sostenla en tus manos y cárgala con la intención de recibir un amor estable y duradero. Colócala en un lugar especial de tu hogar como ancla de tu intención.", r1e:"⛰️", r2n:"Vela Negra y Blanca", r2d:"Enciende una vela negra y una blanca juntas los sábados. La negra disuelve lo que no sirve y la blanca atrae lo nuevo. Visualiza la llegada de un amor maduro, real y completamente comprometido.", r2e:"🕯️", r3n:"Contrato con el Universo", r3d:"Escribe un contrato detallado con el universo describiendo el amor que mereces recibir. Fírmalo con tu nombre. Colócalo en un lugar sagrado de tu hogar y léelo una vez por semana.", r3e:"📜", fin:"Tu determinación y fortaleza merecen un amor igualmente sólido y real. El hombre que llega a tu vida construirá contigo, no solo te amará. Esa base inquebrantable ya está siendo preparada por el universo." },
  "Acuario":     { desc:"Es un hombre único, libre pensador y profundamente auténtico que valorará tu individualidad sin intentar cambiarte. Tiene una mente brillante y una perspectiva del mundo que te sorprenderá constantemente. Es el tipo raro de hombre que ama de verdad sin necesitar poseer, dándote libertad y presencia al mismo tiempo.", h1:"Se conocerán en un contexto inusual o innovador. Quizás a través de la tecnología, en un movimiento social, en un evento diferente o en una comunidad con intereses poco convencionales. La conexión empezará desde las ideas y las convicciones profundas.", h2:"El universo usará algo inesperado para acercarlos. Una coincidencia extraña, una señal que ambos notarán. Será el tipo de encuentro del que hablarán siempre porque tendrá algo de mágico e inexplicable.", r1n:"Ritual del Viento", r1d:"Escribe tu intención de amor en un papel pequeño. Sal a un lugar abierto y suéltalo al viento o quémalo dejando que el humo suba. El viento lleva tus deseos hacia el universo infinito.", r1e:"💨", r2n:"Cristal de Lapislázuli", r2d:"Medita con lapislázuli o turquesa sobre tu tercer ojo durante 10 minutos. Abre tu mente a recibir el amor de formas inesperadas y no convencionales. Tu alma gemela llegará por caminos únicos.", r2e:"💙", r3n:"Ritual Comunitario", r3d:"Haz un acto de bondad desinteresado hacia alguien cada semana. El amor universal que proyectas hacia afuera activa el amor romántico que recibes. Lo que das vuelve multiplicado en amor genuino.", r3e:"🤝", fin:"Tu autenticidad y visión única del mundo son exactamente lo que tu alma gemela está buscando. Él existe en algún rincón del universo con la misma frecuencia que la tuya. Pronto sus mundos colisionarán." },
  "Piscis":      { desc:"Es un hombre sensible y romántico con una conexión espiritual profunda que igualará la tuya. Tiene una intuición extraordinaria y la capacidad de amarte en todas tus dimensiones — la visible y la invisible. Es soñador pero también protector, y contigo encontrará el puerto seguro que siempre ha buscado en silencio.", h1:"Se conocerán en un momento de magia cotidiana — quizás al atardecer, cerca del agua, o en un momento de contemplación. Habrá algo etéreo en el encuentro, como si hubieran salido de un sueño que ambos tuvieron antes.", h2:"Los sueños serán la antesala del encuentro. Quizás lo sientas antes de verlo. Una canción, un sueño vívido, una sensación extraña de que alguien se acerca. El universo te enviará señales antes de que se vean.", r1n:"Ritual del Mar", r1d:"Si puedes ve al mar o a cualquier cuerpo de agua. Escribe su nombre imaginado en la arena o en el agua y di: El amor que me pertenece fluye hacia mí como el agua fluye hacia el mar naturalmente.", r1e:"🌊", r2n:"Meditación Lunar", r2d:"Cada luna llena medita 15 minutos visualizando a tu alma gemela. No necesitas ver su rostro — siente su energía, su calor, su presencia. Esta meditación fortalece el hilo invisible que los une.", r2e:"🌕", r3n:"Ritual del Sueño", r3d:"Antes de dormir escribe en papel: Esta noche conecto con mi alma gemela en el plano espiritual. Colócalo bajo la almohada. Presta atención a tus sueños — contienen mensajes sobre el encuentro que viene.", r3e:"💫", fin:"Tu alma sensible ya siente que él se acerca. Esa intuición tuya nunca miente. El amor más profundo y espiritual que puedas imaginar está siendo tejido para ti. Confía en lo que sientes — el universo te habla." }
};

const stars = Array.from({length:45},(_,i)=>({id:i,x:Math.random()*100,y:Math.random()*100,s:Math.random()*2+0.5,d:Math.random()*3+2,delay:Math.random()*5}));

const CSS = `
@import url('https://fonts.googleapis.com/css2?family=Cinzel:wght@400;700&family=Lora:ital,wght@0,400;1,400&display=swap');
*{box-sizing:border-box;margin:0;padding:0}
input,select,textarea{outline:none;-webkit-appearance:none}
input::placeholder,textarea::placeholder{color:rgba(255,255,255,0.3)}
select option{background:#1a0030;color:white}
::-webkit-scrollbar{width:3px}
::-webkit-scrollbar-thumb{background:#9B6B9E;border-radius:2px}
@keyframes twinkle{0%,100%{opacity:0}50%{opacity:0.85}}
@keyframes float{0%,100%{transform:translateY(0)}50%{transform:translateY(-9px)}}
@keyframes shimmer{0%{background-position:200% center}100%{background-position:-200% center}}
@keyframes fadeUp{from{opacity:0;transform:translateY(20px)}to{opacity:1;transform:translateY(0)}}
@keyframes pulse{0%,100%{opacity:0.7;transform:scale(1)}50%{opacity:1;transform:scale(1.06)}}
@keyframes spin{from{transform:rotate(0deg)}to{transform:rotate(360deg)}}
@keyframes glow{0%,100%{box-shadow:0 0 18px rgba(212,175,55,0.25)}50%{box-shadow:0 0 40px rgba(212,175,55,0.6)}}
`;

function Stars() {
  return (
    <div style={{position:"fixed",inset:0,pointerEvents:"none",zIndex:0}}>
      <style>{CSS}</style>
      {stars.map(s=>(
        <div key={s.id} style={{position:"absolute",left:`${s.x}%`,top:`${s.y}%`,width:s.s,height:s.s,borderRadius:"50%",background:"white",opacity:0,animation:`twinkle ${s.d}s ${s.delay}s infinite`}}/>
      ))}
    </div>
  );
}

function DayProgressBar({startDate}) {
  const now = Date.now();
  const start = new Date(startDate).getTime();
  const diffDays = Math.min(Math.floor((now - start) / (1000*60*60*24)), TOTAL_DAYS);
  const pct = Math.round((diffDays / TOTAL_DAYS) * 100);
  const daysLeft = TOTAL_DAYS - diffDays;
  const [animated, setAnimated] = useState(0);
  useEffect(()=>{let n=0;const t=setInterval(()=>{n+=1;setAnimated(n);if(n>=pct)clearInterval(t)},18);return()=>clearInterval(t)},[pct]);
  const msg = pct>=100?"¡Tu alma gemela ya está en tu camino! 🌟":pct>=75?"La energía del encuentro es muy fuerte...":pct>=50?"El universo está acelerando tu unión...":pct>=25?"Las energías se están alineando...":"Tu camino está siendo trazado por las estrellas...";
  return (
    <div style={{display:"flex",flexDirection:"column",gap:16}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:12}}>
        <div style={{textAlign:"center",flex:1}}>
          <div style={{fontFamily:"Cinzel",fontWeight:700,fontSize:42,color:"#D4AF37",lineHeight:1,animation:"glow 3s ease-in-out infinite"}}>{pct}%</div>
          <div style={{fontFamily:"Cinzel",fontSize:9,letterSpacing:3,color:"rgba(255,255,255,0.4)",marginTop:4}}>PROXIMIDAD</div>
        </div>
        <div style={{width:1,height:50,background:"rgba(212,175,55,0.15)"}}/>
        <div style={{textAlign:"center",flex:1}}>
          <div style={{fontFamily:"Cinzel",fontWeight:700,fontSize:42,color:daysLeft===0?"#D4AF37":"#9B6B9E",lineHeight:1}}>{daysLeft===0?"✦":daysLeft}</div>
          <div style={{fontFamily:"Cinzel",fontSize:9,letterSpacing:3,color:"rgba(255,255,255,0.4)",marginTop:4}}>{daysLeft===0?"LLEGÓ":"DÍAS RESTANTES"}</div>
        </div>
        <div style={{width:1,height:50,background:"rgba(212,175,55,0.15)"}}/>
        <div style={{textAlign:"center",flex:1}}>
          <div style={{fontFamily:"Cinzel",fontWeight:700,fontSize:42,color:"rgba(255,255,255,0.5)",lineHeight:1}}>{diffDays}</div>
          <div style={{fontFamily:"Cinzel",fontSize:9,letterSpacing:3,color:"rgba(255,255,255,0.4)",marginTop:4}}>DÍAS ACTIVA</div>
        </div>
      </div>
      <div>
        <div style={{height:8,background:"rgba(255,255,255,0.07)",borderRadius:99,overflow:"hidden"}}>
          <div style={{height:"100%",width:`${animated}%`,borderRadius:99,background:"linear-gradient(90deg,#9B6B9E,#D4AF37)",boxShadow:"0 0 14px #D4AF3770",transition:"width 0.02s"}}/>
        </div>
        <div style={{display:"flex",justifyContent:"space-between",marginTop:6}}>
          <span style={{fontFamily:"Cinzel",fontSize:8,letterSpacing:2,color:"rgba(255,255,255,0.25)"}}>DÍA 1</span>
          <span style={{fontFamily:"Cinzel",fontSize:8,letterSpacing:2,color:"rgba(255,255,255,0.25)"}}>DÍA {TOTAL_DAYS}</span>
        </div>
      </div>
      <div style={{display:"flex",gap:3,flexWrap:"wrap"}}>
        {Array.from({length:TOTAL_DAYS},(_,i)=>(
          <div key={i} style={{width:`calc(${100/TOTAL_DAYS}% - 2px)`,minWidth:4,height:16,borderRadius:3,background:i<diffDays?"linear-gradient(#D4AF37,#9B6B9E)":"rgba(255,255,255,0.07)"}}/>
        ))}
      </div>
      <p style={{fontFamily:"Lora",fontStyle:"italic",fontSize:13,color:"rgba(255,255,255,0.55)",textAlign:"center",lineHeight:1.6}}>{msg}</p>
    </div>
  );
}

const TABS = [{id:"lectura",icon:"🔮",label:"Mi Lectura"},{id:"rituales",icon:"🕯️",label:"Rituales"},{id:"senales",icon:"✨",label:"Señales"}];

function TabBar({active,onChange}) {
  return (
    <div style={{display:"flex",gap:0,background:"rgba(0,0,0,0.3)",borderRadius:14,padding:4,border:"1px solid rgba(212,175,55,0.15)",marginBottom:20}}>
      {TABS.map(t=>(
        <button key={t.id} onClick={()=>onChange(t.id)} style={{flex:1,padding:"10px 4px",border:"none",borderRadius:11,cursor:"pointer",background:active===t.id?"linear-gradient(135deg,rgba(155,107,158,0.5),rgba(212,175,55,0.3))":"transparent",color:active===t.id?"white":"rgba(255,255,255,0.35)",transition:"all 0.25s",display:"flex",flexDirection:"column",alignItems:"center",gap:4,boxShadow:active===t.id?"0 2px 12px rgba(212,175,55,0.2)":"none"}}>
          <span style={{fontSize:16}}>{t.icon}</span>
          <span style={{fontFamily:"Cinzel",fontSize:8,letterSpacing:1.5,whiteSpace:"nowrap"}}>{t.label}</span>
        </button>
      ))}
    </div>
  );
}

function Card({children,delay=0,style={}}) {
  return <div style={{background:"rgba(255,255,255,0.04)",border:"1px solid rgba(212,175,55,0.16)",borderRadius:16,padding:"20px 18px",animation:`fadeUp 0.6s ${delay}s both`,...style}}>{children}</div>;
}

function ST({icon,title}) {
  return <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:14}}><span style={{fontSize:15}}>{icon}</span><span style={{fontFamily:"Cinzel",fontSize:9,letterSpacing:3,color:"#D4AF37"}}>{title}</span></div>;
}

function TabLectura({res}) {
  const c = CONTENIDO[res.signo] || CONTENIDO["Aries"];
  return (
    <div style={{display:"flex",flexDirection:"column",gap:16}}>
      <div style={{textAlign:"center",padding:"4px 0 8px",animation:"fadeUp 0.6s both"}}>
        <div style={{position:"relative",width:200,margin:"0 auto 16px"}}>
          <div style={{position:"absolute",inset:-3,borderRadius:20,background:"conic-gradient(#D4AF37,#9B6B9E,#E8C4D4,#D4AF37)",animation:"spin 10s linear infinite"}}/>
          <div style={{position:"relative",borderRadius:16,overflow:"hidden",margin:3}}>
            <img src={RETRATO_B64} alt="Tu alma gemela" style={{width:"100%",display:"block",borderRadius:14}}/>
            <div style={{position:"absolute",bottom:0,left:0,right:0,background:"linear-gradient(transparent,rgba(10,0,20,0.85))",padding:"20px 12px 12px",textAlign:"center"}}>
              <div style={{fontFamily:"Cinzel",fontSize:8,letterSpacing:3,color:"#D4AF37"}}>✦ RETRATO DE TU ALMA GEMELA ✦</div>
            </div>
          </div>
        </div>
        <div style={{fontFamily:"Cinzel",fontSize:9,letterSpacing:4,color:"#D4AF37"}}>LECTURA DE {res.signo?.toUpperCase()}</div>
        <div style={{fontFamily:"Lora",fontStyle:"italic",fontSize:12,color:"rgba(255,255,255,0.35)",marginTop:4}}>para {res.nombre}</div>
      </div>
      <Card delay={0.1}><ST icon="🌙" title="PROGRESO DEL ENCUENTRO"/><DayProgressBar startDate={res.startDate}/></Card>
      <Card delay={0.2}><ST icon="🔮" title="DESCRIPCIÓN DE TU ALMA GEMELA"/><p style={{fontFamily:"Lora",fontStyle:"italic",fontSize:14,lineHeight:1.85,color:"rgba(255,255,255,0.85)"}}>"{c.desc}"</p></Card>
      <Card delay={0.3}><ST icon="📖" title="CÓMO SE VAN A CONOCER"/>
        <div style={{display:"flex",flexDirection:"column",gap:12}}>
          {[c.h1,c.h2].map((h,i)=>(
            <div key={i} style={{padding:"13px 15px",background:"rgba(155,107,158,0.08)",borderRadius:10,borderLeft:"2px solid rgba(212,175,55,0.3)"}}>
              <div style={{fontFamily:"Cinzel",fontSize:8,letterSpacing:3,color:"#D4AF37",marginBottom:6}}>VISIÓN {i+1}</div>
              <p style={{fontFamily:"Lora",fontSize:13,lineHeight:1.8,color:"rgba(255,255,255,0.8)"}}>{h}</p>
            </div>
          ))}
        </div>
      </Card>
      <Card delay={0.4} style={{background:"linear-gradient(135deg,rgba(155,107,158,0.1),rgba(212,175,55,0.07))",border:"1px solid rgba(212,175,55,0.25)"}}>
        <div style={{textAlign:"center"}}>
          <div style={{fontSize:20,marginBottom:10}}>💫</div>
          <p style={{fontFamily:"Lora",fontStyle:"italic",fontSize:14,lineHeight:1.85,color:"rgba(255,255,255,0.9)",marginBottom:12}}>{c.fin}</p>
          <div style={{fontFamily:"Cinzel",fontSize:8,letterSpacing:3,color:"#D4AF37"}}>— {res.nombre?.toUpperCase()}, EL UNIVERSO TE VE —</div>
        </div>
      </Card>
    </div>
  );
}

function TabRituales({res}) {
  const c = CONTENIDO[res.signo] || CONTENIDO["Aries"];
  const nowMs = Date.now();
  const startMs = new Date(res.startDate).getTime();
  const daysSince = Math.floor((nowMs - startMs) / (1000*60*60*24));
  const rituais = [
    {e:c.r1e,n:c.r1n,d:c.r1d,when:"Día 1 · Al despertar",unlockDay:0},
    {e:c.r2e,n:c.r2n,d:c.r2d,when:"Día 7 · Antes de dormir",unlockDay:7},
    {e:c.r3e,n:c.r3n,d:c.r3d,when:"Día 14 · Luna llena",unlockDay:14},
  ];
  const [done,setDone]=useState({});
  useEffect(()=>{(async()=>{try{const r=await window.storage.get("rituales-done");if(r)setDone(JSON.parse(r.value));}catch(e){}})();},[]);
  const toggle=async(i)=>{const next={...done,[i]:!done[i]};setDone(next);try{await window.storage.set("rituales-done",JSON.stringify(next));}catch(e){}};
  const completedCount=Object.values(done).filter(Boolean).length;
  return (
    <div style={{display:"flex",flexDirection:"column",gap:16}}>
      <Card>
        <div style={{textAlign:"center"}}>
          <div style={{fontFamily:"Cinzel",fontSize:9,letterSpacing:3,color:"#D4AF37",marginBottom:8}}>TU COMPROMISO DIARIO</div>
          <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:8,marginBottom:8}}>
            {rituais.map((_,i)=><div key={i} style={{width:10,height:10,borderRadius:"50%",background:done[i]?"#D4AF37":"rgba(255,255,255,0.1)",border:"1px solid rgba(212,175,55,0.4)",transition:"all 0.3s"}}/>)}
          </div>
          <div style={{fontFamily:"Lora",fontStyle:"italic",fontSize:12,color:"rgba(255,255,255,0.4)"}}>
            {completedCount===0?"Completa tus rituales para atraer el amor":completedCount===3?"✦ Todos completados — el universo te escucha ✦":`${completedCount} de ${rituais.length} rituales realizados`}
          </div>
        </div>
      </Card>
      {rituais.map((r,i)=>{
        const unlocked=daysSince>=r.unlockDay;
        return (
          <div key={i} onClick={()=>unlocked&&toggle(i)} style={{background:done[i]?"linear-gradient(135deg,rgba(212,175,55,0.12),rgba(155,107,158,0.1))":unlocked?"rgba(255,255,255,0.04)":"rgba(0,0,0,0.2)",border:`1px solid ${done[i]?"rgba(212,175,55,0.35)":unlocked?"rgba(212,175,55,0.14)":"rgba(255,255,255,0.05)"}`,borderRadius:16,padding:"18px 16px",cursor:unlocked?"pointer":"default",transition:"all 0.3s",animation:`fadeUp 0.6s ${i*0.1}s both`,position:"relative",overflow:"hidden"}}>
            {!unlocked&&<div style={{position:"absolute",inset:0,zIndex:3,display:"flex",alignItems:"center",justifyContent:"center",borderRadius:16}}><div style={{textAlign:"center",background:"rgba(10,0,20,0.6)",padding:"8px 18px",borderRadius:10,border:"1px solid rgba(212,175,55,0.15)"}}><div style={{fontSize:16,marginBottom:3}}>🔒</div><div style={{fontFamily:"Cinzel",fontSize:8,letterSpacing:2,color:"rgba(212,175,55,0.6)"}}>SE LIBERA EN EL DÍA {r.unlockDay}</div></div></div>}
            <div style={{display:"flex",alignItems:"flex-start",gap:12,filter:unlocked?"none":"blur(3px)"}}>
              <div style={{fontSize:26}}>{r.e}</div>
              <div style={{flex:1}}>
                <div style={{fontFamily:"Cinzel",fontSize:10,letterSpacing:2,color:done[i]?"#D4AF37":"rgba(212,175,55,0.7)",fontWeight:700,marginBottom:4}}>{r.n}</div>
                <div style={{fontFamily:"Cinzel",fontSize:8,letterSpacing:2,color:"rgba(255,255,255,0.3)",marginBottom:8}}>{r.when}</div>
                <p style={{fontFamily:"Lora",fontSize:13,lineHeight:1.7,color:done[i]?"rgba(255,255,255,0.85)":"rgba(255,255,255,0.65)"}}>{r.d}</p>
              </div>
            </div>
            {unlocked&&<div style={{marginTop:10,textAlign:"center",fontFamily:"Cinzel",fontSize:8,letterSpacing:2,color:done[i]?"rgba(212,175,55,0.5)":"rgba(255,255,255,0.2)"}}>{done[i]?"✓ RITUAL COMPLETADO — toca para desmarcar":"toca para marcar como completado"}</div>}
            {done[i]&&<div style={{position:"absolute",top:10,right:12,fontSize:14,color:"#D4AF37"}}>✓</div>}
          </div>
        );
      })}
    </div>
  );
}

function TabSenales({res}) {
  const now=Date.now();
  const start=new Date(res.startDate).getTime();
  const diffDays=Math.floor((now-start)/(1000*60*60*24));
  const signals=[
    {day:1,icon:"🌙",title:"Primera Señal",desc:"Presta atención a tus sueños esta semana. Tu alma gemela podría aparecer en ellos antes del encuentro físico."},
    {day:3,icon:"🔢",title:"Números del Ángel",desc:"Cuando veas 11:11, 2:22 o 3:33 en el reloj, el universo te confirma que el encuentro se acerca. Para y sonríe."},
    {day:7,icon:"🌹",title:"La Señal del Color",desc:"El color favorito de tu alma gemela aparecerá repetidamente en tu vida. Observa qué color ves con más frecuencia."},
    {day:14,icon:"🦋",title:"El Mensajero",desc:"Una mariposa, una pluma o una moneda encontrada en tu camino es un mensaje del universo: estás en el camino correcto."},
    {day:21,icon:"⭐",title:"La Canción",desc:"Escucharás una canción en el momento exacto que necesitas. Esa canción será la melodía de vuestro encuentro."},
    {day:30,icon:"🌊",title:"El Sueño Revelador",desc:"Entre los días 30 y 40 tendrás un sueño muy vívido. Escríbelo al despertar — contiene información sobre dónde se conocerán."},
    {day:40,icon:"🔥",title:"La Energía Cambia",desc:"Sentirás una energía diferente, una inquietud inexplicable. Es tu alma sintonizándose con la de él. El encuentro es inminente."},
    {day:47,icon:"💫",title:"El Gran Encuentro",desc:"El universo ha completado su trabajo. Mantente presente, abierta y con el corazón disponible. Lo que es tuyo, llega."},
  ];
  return (
    <div style={{display:"flex",flexDirection:"column",gap:12}}>
      <Card><div style={{textAlign:"center"}}><div style={{fontFamily:"Cinzel",fontSize:9,letterSpacing:3,color:"#D4AF37",marginBottom:6}}>SEÑALES DEL UNIVERSO</div><p style={{fontFamily:"Lora",fontStyle:"italic",fontSize:13,color:"rgba(255,255,255,0.5)",lineHeight:1.6}}>Las señales se revelan conforme avanza tu camino. Llevas {diffDays} día{diffDays!==1?"s":""} en tu jornada.</p></div></Card>
      {signals.map((s,i)=>{
        const unlocked=diffDays>=s.day;
        return (
          <div key={i} style={{background:unlocked?"rgba(255,255,255,0.05)":"rgba(0,0,0,0.25)",border:`1px solid ${unlocked?"rgba(212,175,55,0.2)":"rgba(255,255,255,0.06)"}`,borderRadius:14,padding:"16px 16px",animation:`fadeUp 0.5s ${i*0.07}s both`,position:"relative",overflow:"hidden"}}>
            {!unlocked&&<div style={{position:"absolute",inset:0,zIndex:3,display:"flex",alignItems:"center",justifyContent:"center",borderRadius:14}}><div style={{textAlign:"center",background:"rgba(10,0,20,0.5)",padding:"8px 16px",borderRadius:10,border:"1px solid rgba(212,175,55,0.15)"}}><div style={{fontSize:16,marginBottom:3}}>🔒</div><div style={{fontFamily:"Cinzel",fontSize:8,letterSpacing:2,color:"rgba(212,175,55,0.6)"}}>SE REVELA EN EL DÍA {s.day}</div></div></div>}
            <div style={{display:"flex",gap:12,alignItems:"flex-start",filter:unlocked?"none":"blur(4px)"}}>
              <div style={{fontSize:24,minWidth:32,textAlign:"center"}}>{s.icon}</div>
              <div>
                <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:5}}>
                  <span style={{fontFamily:"Cinzel",fontSize:10,letterSpacing:2,color:"#D4AF37"}}>{s.title}</span>
                  {unlocked&&<span style={{fontFamily:"Cinzel",fontSize:7,letterSpacing:1,color:"rgba(212,175,55,0.5)",background:"rgba(212,175,55,0.1)",padding:"2px 6px",borderRadius:99}}>DÍA {s.day}</span>}
                </div>
                <p style={{fontFamily:"Lora",fontSize:13,lineHeight:1.7,color:"rgba(255,255,255,0.75)"}}>{s.desc}</p>
              </div>
            </div>
          </div>
        );
      })}
    </div>
  );
}

export default function App() {
  const [step,setStep]=useState("boot");
  const [form,setForm]=useState({nombre:"",signo:""});
  const [res,setRes]=useState(null);
  const [tab,setTab]=useState("lectura");

  useEffect(()=>{
    (async()=>{
      try{const saved=await window.storage.get("alma-gemela-reading");if(saved&&saved.value){setRes(JSON.parse(saved.value));setStep("app");}else{setStep("form");}}catch(e){setStep("form");}
    })();
  },[]);

  const run=async()=>{
    if(!form.nombre||!form.signo) return;
    const reading={nombre:form.nombre,signo:form.signo,startDate:new Date().toISOString()};
    try{await window.storage.set("alma-gemela-reading",JSON.stringify(reading));}catch(e){}
    setRes(reading);
    setStep("app");
  };

  const inp={width:"100%",background:"rgba(255,255,255,0.06)",border:"1px solid rgba(212,175,55,0.2)",borderRadius:12,padding:"13px 15px",color:"white",fontFamily:"Lora",fontSize:15};
  const lbl={display:"block",marginBottom:7,fontFamily:"Cinzel",fontSize:10,letterSpacing:3,color:"#D4AF37"};

  return (
    <div style={{minHeight:"100vh",background:"radial-gradient(ellipse at 30% 10%,#2d0f5e,#0d0118 50%,#0a000f)",color:"white",fontFamily:"Lora",position:"relative",overflow:"hidden"}}>
      <Stars/>
      <div style={{position:"fixed",top:"-15%",right:"-5%",width:300,height:300,borderRadius:"50%",background:"radial-gradient(rgba(155,107,158,0.1),transparent 70%)",pointerEvents:"none",zIndex:0}}/>
      <div style={{position:"relative",zIndex:1,maxWidth:420,margin:"0 auto",padding:"0 18px 80px"}}>
        <div style={{textAlign:"center",padding:"36px 0 22px",animation:"fadeUp 0.7s both"}}>
          <div style={{fontSize:24,animation:"float 3s ease-in-out infinite",marginBottom:8}}>✦</div>
          <h1 style={{margin:0,fontFamily:"Cinzel",fontWeight:700,fontSize:"clamp(22px,6vw,30px)",letterSpacing:5,background:"linear-gradient(135deg,#D4AF37,#E8C4D4,#9B6B9E)",WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent",backgroundSize:"200%",animation:"shimmer 4s linear infinite"}}>ALMA GEMELA</h1>
          <div style={{fontFamily:"Lora",fontStyle:"italic",color:"rgba(255,255,255,0.4)",fontSize:12,marginTop:6}}>El universo ya escribió tu historia de amor</div>
        </div>

        {step==="boot"&&<div style={{textAlign:"center",padding:40,color:"rgba(255,255,255,0.3)",fontFamily:"Cinzel",fontSize:10,letterSpacing:3}}>CARGANDO...</div>}

        {step==="form"&&(
          <div style={{display:"flex",flexDirection:"column",gap:16,animation:"fadeUp 0.7s 0.1s both"}}>
            <div style={{background:"rgba(255,255,255,0.04)",border:"1px solid rgba(212,175,55,0.16)",borderRadius:16,padding:"22px 18px",display:"flex",flexDirection:"column",gap:16}}>
              <div style={{textAlign:"center",marginBottom:4}}>
                <div style={{fontFamily:"Cinzel",fontSize:11,letterSpacing:3,color:"#D4AF37"}}>TU LECTURA PERSONAL</div>
                <div style={{fontFamily:"Lora",fontStyle:"italic",color:"rgba(255,255,255,0.3)",fontSize:12,marginTop:5}}>Esta lectura es única e irrepetible para ti</div>
              </div>
              <div><label style={lbl}>TU NOMBRE</label><input style={inp} placeholder="¿Cómo te llamas?" value={form.nombre} onChange={e=>setForm(f=>({...f,nombre:e.target.value}))}/></div>
              <div><label style={lbl}>TU SIGNO SOLAR</label>
                <select style={{...inp,cursor:"pointer"}} value={form.signo} onChange={e=>setForm(f=>({...f,signo:e.target.value}))}>
                  <option value="">Selecciona tu signo...</option>
                  {SIGNOS.map(s=><option key={s} value={s}>{s}</option>)}
                </select>
              </div>
            </div>
            <button onClick={run} disabled={!form.nombre||!form.signo} style={{padding:"17px",border:"none",borderRadius:14,cursor:form.nombre&&form.signo?"pointer":"not-allowed",background:form.nombre&&form.signo?"linear-gradient(135deg,#9B6B9E,#D4AF37)":"rgba(255,255,255,0.07)",color:"white",fontFamily:"Cinzel",fontSize:11,fontWeight:700,letterSpacing:4,opacity:form.nombre&&form.signo?1:0.4,boxShadow:form.nombre&&form.signo?"0 6px 28px rgba(212,175,55,0.22)":"none",transition:"all 0.3s"}}>
              ✦ REVELAR MI ALMA GEMELA ✦
            </button>
            <p style={{textAlign:"center",fontFamily:"Lora",fontStyle:"italic",fontSize:11,color:"rgba(255,255,255,0.18)",marginTop:4}}>Más de 47.000 almas ya encontraron su camino</p>
          </div>
        )}

        {step==="app"&&res&&(
          <div style={{animation:"fadeUp 0.6s both"}}>
            <TabBar active={tab} onChange={setTab}/>
            {tab==="lectura"&&<TabLectura res={res}/>}
            {tab==="rituales"&&<TabRituales res={res}/>}
            {tab==="senales"&&<TabSenales res={res}/>}
          </div>
        )}
      </div>
    </div>
  );
}
